import{_ as r,o,c as n,ag as l}from"./chunks/framework.BbyMWZAR.js";const p=JSON.parse('{"title":"排序算法对比：稳定性、复杂度与选型","description":"","frontmatter":{"title":"排序算法对比：稳定性、复杂度与选型","difficulty":"medium","tags":["排序","稳定性","快排","归并","堆排"],"estimate":20},"headers":[],"relativePath":"domains/algorithms/qa/qa-02-sorting-comparison.md","filePath":"domains/algorithms/qa/qa-02-sorting-comparison.md","lastUpdated":1783504823000}'),i={name:"domains/algorithms/qa/qa-02-sorting-comparison.md"};function d(s,t,a,g,e,h){return o(),n("div",null,[...t[0]||(t[0]=[l('<h1 id="问答-02-进阶-排序算法对比-稳定性、复杂度与选型" tabindex="-1">问答 02（进阶）：排序算法对比：稳定性、复杂度与选型 <a class="header-anchor" href="#问答-02-进阶-排序算法对比-稳定性、复杂度与选型" aria-label="Permalink to &quot;问答 02（进阶）：排序算法对比：稳定性、复杂度与选型&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>请对比冒泡、选择、插入、快排、归并、堆排、计数、桶、基数排序在时间复杂度、空间复杂度、稳定性上的差异，说明它们各自适合的场景。为什么 <code>Array.prototype.sort</code> 在 V8 中最终选了 TimSort？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>核心对比表</strong></p><table tabindex="0"><thead><tr><th>算法</th><th>平均</th><th>最坏</th><th>最好</th><th>空间</th><th>稳定</th><th>原地</th></tr></thead><tbody><tr><td>冒泡</td><td>O(n²)</td><td>O(n²)</td><td>O(n)</td><td>O(1)</td><td>是</td><td>是</td></tr><tr><td>选择</td><td>O(n²)</td><td>O(n²)</td><td>O(n²)</td><td>O(1)</td><td>否</td><td>是</td></tr><tr><td>插入</td><td>O(n²)</td><td>O(n²)</td><td>O(n)</td><td>O(1)</td><td>是</td><td>是</td></tr><tr><td>希尔</td><td>O(n^1.3)</td><td>O(n²)</td><td>O(n)</td><td>O(1)</td><td>否</td><td>是</td></tr><tr><td>快排</td><td>O(n log n)</td><td>O(n²)</td><td>O(n log n)</td><td>O(log n)</td><td>否</td><td>是</td></tr><tr><td>归并</td><td>O(n log n)</td><td>O(n log n)</td><td>O(n log n)</td><td>O(n)</td><td>是</td><td>否</td></tr><tr><td>堆排</td><td>O(n log n)</td><td>O(n log n)</td><td>O(n log n)</td><td>O(1)</td><td>否</td><td>是</td></tr><tr><td>计数</td><td>O(n+k)</td><td>O(n+k)</td><td>O(n+k)</td><td>O(n+k)</td><td>是</td><td>否</td></tr><tr><td>桶排</td><td>O(n+k)</td><td>O(n²)</td><td>O(n+k)</td><td>O(n+k)</td><td>是</td><td>否</td></tr><tr><td>基数</td><td>O(nk)</td><td>O(nk)</td><td>O(nk)</td><td>O(n+k)</td><td>是</td><td>否</td></tr></tbody></table><p><strong>稳定性的定义</strong></p><ul><li>排序后，<strong>相等元素的相对顺序不变</strong>称为稳定。</li><li>稳定性在<strong>多关键字排序</strong>中非常重要：先按次要字段排序，再按主要字段排序，最终结果仍会保持次要字段的顺序（前提是主排序稳定）。</li></ul><p><strong>各算法要点</strong></p><ul><li><strong>冒泡</strong>：相邻比较交换，简单但慢。改进：加 flag 提前退出。</li><li><strong>选择</strong>：每轮选最小放前面，交换次数少（适合交换代价高的场景），但比较次数固定 O(n²)。</li><li><strong>插入</strong>：适合<strong>小规模或基本有序</strong>的数组，最好 O(n)。TimSort 内部小段用它。</li><li><strong>快排</strong>：分治，选 pivot 划分。平均性能最佳，但最坏 O(n²)（极端有序 + 固定 pivot）。工程实现常用三数取中、随机化 pivot、小区间切插入排序。</li><li><strong>归并</strong>：稳定的分治排序，性能稳定，缺点是需 O(n) 辅助空间。链表归并可以做到 O(1) 空间。</li><li><strong>堆排</strong>：原地、最坏 O(n log n)，但缓存不友好、常数大，实际比快排慢。适合 top-K 场景（用堆，不用全排）。</li><li><strong>计数</strong>：非比较排序，要求键为有限整数范围 [0, k]，O(n+k)。k 太大不划算。</li><li><strong>桶排</strong>：按值域分桶，桶内再排。分布均匀时 O(n)。</li><li><strong>基数</strong>：按位分桶，多轮稳定排序完成整体排序。适合整数、定长字符串。</li></ul><p><strong>为什么 V8 选 TimSort</strong></p><ul><li><strong>TimSort</strong> 是 Python 发明的、结合归并与插入的自适应稳定排序。</li><li>特点： <ul><li><strong>稳定</strong>（ES2019 规范要求 <code>Array.prototype.sort</code> 必须稳定）。</li><li>对<strong>已有序或部分有序</strong>的数据表现极好（识别 run 并归并），最好 O(n)。</li><li>最坏 O(n log n)，性能可预期。</li><li>归并使用「galloping mode」减少比较次数。</li></ul></li><li>V8 早年是 QuickSort（不稳定），2018 起改用 TimSort（V8 v7.0），从此规范和实现都稳定。</li></ul><p><strong>选型指导</strong></p><ul><li><strong>小数组（&lt;= 10~20 项）</strong>：插入排序，常数小。</li><li><strong>一般通用</strong>：TimSort / 快排（有语言内建就用内建）。</li><li><strong>需要稳定</strong>：归并 / TimSort。</li><li><strong>数据量极大且内存紧张</strong>：堆排 / 原地快排。</li><li><strong>整数、值域小</strong>：计数 / 基数排序。</li><li><strong>只要 top-K</strong>：堆（大小 K 的小顶堆），O(n log K)。</li><li><strong>外排序（数据超内存）</strong>：多路归并 + 磁盘 IO 优化。</li></ul><h2 id="追问-1-快排的最坏情况是什么-如何避免" tabindex="-1">追问 1：快排的最坏情况是什么？如何避免？ <a class="header-anchor" href="#追问-1-快排的最坏情况是什么-如何避免" aria-label="Permalink to &quot;追问 1：快排的最坏情况是什么？如何避免？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>最坏是每次划分极不均匀，例如<strong>每次都选到当前区间的最小/最大值作 pivot</strong>（对已排序数组用「取首元素」pivot 就会发生），递归深度 O(n)，比较次数 O(n²)，还可能栈溢出。</li><li>避免方法： <ol><li><strong>随机化 pivot</strong>：随机取一个元素与首交换后再划分，让最坏情况几乎不发生。</li><li><strong>三数取中</strong>：取首、尾、中三个元素的中位数作 pivot。</li><li><strong>小区间切插入排序</strong>（一般阈值 10~16），减少递归开销。</li><li><strong>三路划分</strong>（Dutch National Flag）：处理大量重复值时把等于 pivot 的段一次跳过，避免退化。</li><li><strong>尾递归/迭代 + 短端优先递归</strong>：只对小的一侧递归，大的一侧循环处理，把栈深度限制在 O(log n)。</li></ol></li></ul><h2 id="追问-2-为什么归并排序空间是-o-n-而堆排是-o-1-归并可以做到原地吗" tabindex="-1">追问 2：为什么归并排序空间是 O(n) 而堆排是 O(1)？归并可以做到原地吗？ <a class="header-anchor" href="#追问-2-为什么归并排序空间是-o-n-而堆排是-o-1-归并可以做到原地吗" aria-label="Permalink to &quot;追问 2：为什么归并排序空间是 O(n) 而堆排是 O(1)？归并可以做到原地吗？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>归并</strong>要在合并两个已排序子数组时借助一个临时缓冲区，缓冲区大小与被合并区间成正比，最坏 O(n)。</li><li><strong>堆排</strong>在原数组上就能建堆、下沉，交换即可，不需要额外数组，空间 O(1)（递归/循环开销可忽略）。</li><li>归并<strong>可以做到 O(1) 空间</strong>（原地归并），但常见实现要么破坏稳定性，要么让时间常数变得非常大（比如块交换法 O(n log n) 但常数极大），工程价值不高。<strong>链表归并</strong>天然 O(1) 空间——不需要拷贝，只调整指针。</li></ul><h2 id="追问-3-数据量-1-亿、内存只有-100-mb-如何排序" tabindex="-1">追问 3：数据量 1 亿、内存只有 100 MB，如何排序？ <a class="header-anchor" href="#追问-3-数据量-1-亿、内存只有-100-mb-如何排序" aria-label="Permalink to &quot;追问 3：数据量 1 亿、内存只有 100 MB，如何排序？&quot;">​</a></h2><p><strong>答</strong>：这是典型的<strong>外部排序</strong>问题，思路是<strong>分治 + 多路归并</strong>：</p><ol><li><strong>分块内排</strong>：把大文件按内存能装下的大小（如 80 MB）读进来，用内存排序（快排/TimSort）后写回磁盘，形成多个已排序小文件（run）。</li><li><strong>多路归并</strong>：用<strong>小顶堆</strong>同时维护每个 run 当前最小元素，每次弹出堆顶写到输出文件，再从对应 run 补一个新元素进堆，直到所有 run 消耗完。</li><li><strong>优化点</strong>： <ul><li>每个 run 用<strong>缓冲区批量读写</strong>减少磁盘 IO；</li><li><strong>败者树</strong>代替普通堆减少比较次数；</li><li>如果数据是整数且值域已知，可考虑<strong>基数排序</strong>或<strong>外部计数排序</strong>；</li><li>分布式场景下用 MapReduce 或 Spark 做 shuffle 排序，本质仍是分块 + 归并。</li></ul></li></ol><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/algorithms/RESOURCES">算法 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://mitpress.mit.edu/9780262046305/introduction-to-algorithms/" target="_blank" rel="noreferrer">CLRS (Introduction to Algorithms)</a>：排序算法正确性证明、稳定性与最坏/平均复杂度分析</li><li><a href="https://oi-wiki.org/basic/sort-intro/" target="_blank" rel="noreferrer">OI Wiki: 排序简介</a>：各排序算法对比与选型，含 TimSort 背景</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Array/sort" target="_blank" rel="noreferrer">MDN: Array.prototype.sort</a>：V8 TimSort 实现与 ES2019 稳定性要求</li><li><a href="https://visualgo.net/en/sorting" target="_blank" rel="noreferrer">VisuAlgo: Sorting</a>：可视化观察 partition、merge、heapify 过程</li></ul>',26)])])}const u=r(i,[["render",d]]);export{p as __pageData,u as default};
